import React, { useState } from 'react';
import { useParams } from 'react-router-dom';
import { Star } from 'lucide-react';
import '../styles/Katalog.css';

const DetailProduk = ({ tambahKeKeranjang }) => {
  const { id } = useParams();
  const [jumlahBeli, setJumlahBeli] = useState(1);

  const produkList = [
    { id: 1, nama: 'Black Forest Cake', harga: 'Rp 150.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1606890737304-57a1ca8a5b62?auto=format&fit=crop&q=80', deskripsi: 'Kue Black Forest klasik dengan bolu cokelat lembut, dilapisi krim segar dan selai ceri asli. Dihiasi dengan serutan cokelat tebal dan buah ceri segar di atasnya. Ukuran: Diameter 20cm (Cocok untuk 8-10 potong).', stok: 15 },
    { id: 2, nama: 'Cheesecake', harga: 'Rp 85.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1533134242443-d4fd215305ad?auto=format&fit=crop&q=80', deskripsi: 'Cheesecake panggang dengan tekstur sangat lembut dan lumer di mulut. Dibuat dari cream cheese premium pilihan dengan alas biskuit mentega yang renyah.', stok: 10 },
    { id: 3, nama: 'Tiramisu Dessert Box', harga: 'Rp 45.000', kategori: 'Dessert Box', img: 'https://images.unsplash.com/photo-1571115177098-24edf3e00b65?auto=format&fit=crop&q=80', deskripsi: 'Dessert box tiramisu khas Italia dengan lapisan lady finger yang direndam kopi espresso murni, dipadukan dengan krim mascarpone tebal dan taburan bubuk kakao.', stok: 20 },
    { id: 4, nama: 'Nastar Keju Premium', harga: 'Rp 120.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1605335967732-2b6389fccb8c?auto=format&fit=crop&q=80', deskripsi: 'Kue kering nastar dengan isian selai nanas asli yang melimpah. Adonan kulitnya dicampur dengan keju edam sehingga menghasilkan perpaduan rasa manis dan gurih.', stok: 25 },
    { id: 5, nama: 'Red Velvet Cake', harga: 'Rp 140.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1616541823729-00fe0aacd32c?auto=format&fit=crop&q=80', deskripsi: 'Bolu Red Velvet berlapis dengan olesan cream cheese frosting yang melimpah dan tidak eneg. Memiliki warna merah merona yang menggugah selera.', stok: 8 },
    { id: 6, nama: 'Bolu Cukke\'', harga: 'Rp 60.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1587241321921-91a834d6d191?auto=format&fit=crop&q=80', deskripsi: 'Bolu Cukke tradisional khas daerah dengan bahan dasar gula merah murni pilihan. Memiliki tekstur padat namun lembut saat digigit, sangat cocok untuk teman minum teh.', stok: 15 }
  ];

  const produk = produkList.find(p => p.id === parseInt(id));

  if (!produk) {
    return (
      <div className="katalog-wrapper" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
        <div className="katalog-overlay"></div>
        <div style={{ position: 'relative', zIndex: 10, background: 'white', padding: '40px', borderRadius: '8px' }}>
          <h2>Produk tidak ditemukan</h2>
        </div>
      </div>
    );
  }

  const aturJumlah = (angka) => {
    const nilaiBaru = jumlahBeli + angka;
    if (nilaiBaru >= 1 && nilaiBaru <= produk.stok) {
      setJumlahBeli(nilaiBaru);
    }
  };

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      
      <div className="katalog-content" style={{ flexDirection: 'column', gap: '15px' }}>
        <div style={{ fontSize: '13px', color: '#e5e7eb', paddingLeft: '5px' }}>
          Beranda / {produk.kategori} / {produk.nama}
        </div>

        <div style={{ display: 'flex', background: 'white', borderRadius: '12px', overflow: 'hidden', width: '100%', padding: '30px', gap: '40px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          
          <div style={{ flex: '1', display: 'flex', flexDirection: 'column', gap: '15px' }}>
            <img src={produk.img} alt={produk.nama} style={{ width: '100%', height: '350px', objectFit: 'cover', borderRadius: '8px' }} />
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '10px' }}>
              <img src={produk.img} alt="thumb-1" style={{ width: '100%', height: '80px', objectFit: 'cover', borderRadius: '6px', border: '2px solid #b45309' }} />
              <img src={produk.img} alt="thumb-2" style={{ width: '100%', height: '80px', objectFit: 'cover', borderRadius: '6px', opacity: '0.7' }} />
              <img src={produk.img} alt="thumb-3" style={{ width: '100%', height: '80px', objectFit: 'cover', borderRadius: '6px', opacity: '0.7' }} />
              <img src={produk.img} alt="thumb-4" style={{ width: '100%', height: '80px', objectFit: 'cover', borderRadius: '6px', opacity: '0.7' }} />
            </div>
          </div>

          <div style={{ flex: '1', display: 'flex', flexDirection: 'column' }}>
            <h1 style={{ margin: '0 0 10px 0', fontSize: '28px', color: '#111' }}>{produk.nama}</h1>
            <h2 style={{ margin: '0 0 15px 0', fontSize: '24px', color: '#111' }}>{produk.harga}</h2>
            
            <div style={{ display: 'flex', gap: '2px', marginBottom: '30px' }}>
              {[...Array(5)].map((_, i) => (
                <Star key={i} size={16} fill="#eab308" color="#eab308" />
              ))}
            </div>

            <div style={{ borderTop: '1px solid #eee', paddingTop: '20px', marginBottom: '30px' }}>
              <h4 style={{ margin: '0 0 10px 0', fontSize: '15px', color: '#333' }}>Deskripsi Produk</h4>
              <p style={{ margin: '0', fontSize: '14px', color: '#666', lineHeight: '1.6' }}>
                {produk.deskripsi}
              </p>
            </div>

            <div style={{ borderTop: '1px solid #eee', paddingTop: '20px', marginTop: 'auto' }}>
              <h4 style={{ margin: '0 0 15px 0', fontSize: '14px', color: '#333' }}>Atur Jumlah</h4>
              <div style={{ display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '25px' }}>
                <div style={{ display: 'flex', alignItems: 'center', border: '1px solid #ddd', borderRadius: '6px', overflow: 'hidden', height: '36px' }}>
                  <button onClick={() => aturJumlah(-1)} style={{ width: '36px', height: '100%', background: 'white', border: 'none', borderRight: '1px solid #ddd', cursor: 'pointer', fontSize: '18px', color: '#555' }}>-</button>
                  <span style={{ width: '50px', textAlign: 'center', fontSize: '15px', fontWeight: 'bold', color: '#111' }}>{jumlahBeli}</span>
                  <button onClick={() => aturJumlah(1)} style={{ width: '36px', height: '100%', background: 'white', border: 'none', borderLeft: '1px solid #ddd', cursor: 'pointer', fontSize: '18px', color: '#555' }}>+</button>
                </div>
                <span style={{ fontSize: '13px', color: '#666' }}>Stok tersedia: {produk.stok}</span>
              </div>

              <button 
                onClick={() => tambahKeKeranjang(produk, jumlahBeli)}
                style={{ width: '100%', padding: '15px', background: '#b45309', color: 'white', border: 'none', borderRadius: '8px', fontSize: '15px', fontWeight: 'bold', cursor: 'pointer', transition: 'background 0.3s' }}
              >
                + Masukkan Keranjang
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default DetailProduk;
